var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"피고는 우리 회사에 안긴 막대한 손실을 어떻게 배상할 것인지 말해보도록.","JPN":"被告は我が社に与えた莫大な損失をどうやって賠償するか説明するように。","ENG":"The defendant shall state her plans for indemnifying the company for such tremendous losses.","TWN":"請被告說明看看如何賠償我們公司巨大的損失。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"배상이라니? 다짜고짜 그게 무슨 소리야?","JPN":"賠償？　急に何を言ってるの？","ENG":"Indemnify? What the heck are you talking about?","TWN":"賠償？沒頭沒尾的這樣說是什麼意思？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L5_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"변명만 늘어놔봤자 좋을 게 없다네.","JPN":"言い訳は許さぬ。","ENG":"Excuses will get you anywhere.","TWN":"光是辯解也沒什麼好處。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"우리 회사는 지난 수년동안 단 한 번도 손익분기점을 넘기지 못했지.","JPN":"我が社はここ数年間、一度も損益分岐点を超えることはできなかった。","ENG":"For years, this company has never surpassed the break-even point.","TWN":"我們公司過去幾年一次都沒有出現盈虧失衡的問題。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"그건 내부에 초대받지 않은 스파이가 있지 않는 한 말이 안 되는 얘기야.","JPN":"それは内部にスパイでもいない限り、有り得ないことである。","ENG":"That didn't make sense, unless there was a spy among us.","TWN":"如果內部沒有出現間諜的話，是絕不可能發生的事情。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"그리고 마침내 자네라는 존재가 수면 위로 모습을 드러냈지!","JPN":"そしてついに、君という存在が姿を現したのだ！","ENG":"And you showed up, as if to prove my hypothesis!","TWN":"然後你的存在偏偏在這時候浮出了水面！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"직원이 아닌 자가 회사를 멋대로 들쑤시고 다니는데 그게 스파이가 아니면 뭐겠나?","JPN":"社員でもない者が社内のあちこちを勝手にかき回しておいて、それがスパイでなければ何だというのだ？","ENG":"Only a spy would go snooping around like you! Especially when you're not even an employee!","TWN":"不是公司員工的人隨便亂闖公司，如果不是間諜又會是什麼呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"뭐야 그게! 억울해! 난 애초에 이쪽 세계에서 살던 사람도 아니라고!","JPN":"はあ？　そんなの理不尽すぎる！　そもそも私はこっちの世界の人間じゃないよ！","ENG":"That's absurd! I'm not even from this world in the first place!","TWN":"什麼啊！這也太冤枉了啊！ 我根本就不是住在這個世界的人！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"하!","JPN":"はっ！","ENG":"Hah!","TWN":"哈！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"그거 참 흔해 빠진 변명이로군!","JPN":"実にありふれた言い訳だな！","ENG":"That's such a common excuse!","TWN":"那還真是常見的辯解啊！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"죄를 인정하지 않겠다면 어쩔 수 없지!","JPN":"罪を認めないなら仕方ない！","ENG":"Well, if you won't admit to your guilt, you leave me no choice!","TWN":"如果不想認罪的話也沒辦法了！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"죄를 뉘우칠 때까지 감옥에 가둬 두는 수 밖에!","JPN":"反省するまで檻に閉じ込めておくとしよう！","ENG":"I will have you jailed until you make penance!","TWN":"只能關在監獄裡直到你認罪為止。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그런 순억지가 어딨어!","JPN":"そんなのおかしいって！","ENG":"That's irrational!","TWN":"哪有這麼不講理的！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"애초에 그쪽은 대표라면서 대체 정체가 뭐야? 왜 혼자 그림체가 다른 건데?","JPN":"そもそも社長とか言ってるけど、いったい何者なの？　なんで一人だけ絵柄が違うの？","ENG":"What's your deal anyway? How come only your art style is different?","TWN":"你一開始就說自己是代表，但你到底是什麼人啊？ 爲什麼只有你一個人的畫風不同？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"그럼 나의 델리케잇한 보디를 어떻게 다른 그림체로 표현한다는 거지?","JPN":"じゃあ、このデリケートなボディーをどうやって他の絵柄で表現するというのかね？","ENG":"Well, how else would you express my delicate body?","TWN":"那怎樣用不同的畫風來表現我如此修長的身體呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"계속 헛소리만 늘어놓는 걸 보니 확신이 드는군!","JPN":"戯れ言ばかり言っている様子を見て確信した！","ENG":"All your gibberish makes me even more certain!","TWN":"看你一直胡說八道，我就越來越肯定了！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"자넨 우리 회사에 훼방을 놓으러 온 불순분자가 틀림없어!","JPN":"やはり君が我が社を危機に陥れたスパイに間違いない！","ENG":"You must be a rogue element seeking to disrupt the company's activities!","TWN":"你一定是來攪亂我們公司的不良分子！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"유죄! 유죄! 유죄!","JPN":"有罪！　有罪！　有罪！","ENG":"Guilty! Guilty! Guilty!","TWN":"有罪！有罪！有罪！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"죄인을 당장 투옥시키도록!","JPN":"罪人を今すぐ投獄せよ！","ENG":"Incarcerate the convict at once!","TWN":"請求馬上把犯人送進監獄！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"미나 양? 유감스럽지만, 순순히 투옥되어 주셔야겠어요.","JPN":"ミナさん？　残念ですが、大人しく投獄されてください。","ENG":"Sorry Mina, but I'm going to have to jail you.","TWN":"米娜小姐？雖然很遺憾，但還是乖乖入獄吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"크윽! 웃기지 마! 내가 순순히 끌려갈 것 같아?","JPN":"は？　ふざけないで！　そんな簡単に納得すると思う？","ENG":"Don't be absurd! You think I'll let you just drag me to jail?","TWN":"呃呃！這太可笑了！你覺得我會乖乖被帶走嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"이렇게 된 이상, 누가 옳은 건지 건틀렛으로 승부를 보자고!","JPN":"こうなった以上、誰が正しいかガントレットで勝負しよう！","ENG":"Why don't we settle this once and for all with a Gauntlet?","TWN":"既然這樣，看誰對誰錯用聖鎧一決勝負吧！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"흥! 죄인 주제에 그런 터무니없는......","JPN":"ふん！　罪人のくせに生意気な……","ENG":"Hmpf! You don't get to make demands—","TWN":"哼！身為罪人這要求也太荒謬了……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"재밌겠구나! 그렇다면 경기의 심판은 이 몸이 맡도록 하지.","JPN":"面白そうじゃな！　ならばガントレットの審判は妾が務めるとしよう。","ENG":"That sounds most amusing! Then I shall adjudicate as the referee.","TWN":"感覺真有趣！那比賽的裁判就由我來擔任吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_NPC_FOOLSDAY_NULL","text":{"KOREA":"막 들어온 신입 주제에 대표에게 도전장을 내밀다니, 꽤 하는군.","JPN":"入ったばかりの新人のくせに社長に挑むとは、なかなかやるな。","ENG":"You got some nerve challenging the CEO, rookie.","TWN":"剛進來的菜鳥竟敢向代表發出挑戰，真是太猛了。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"HILDE_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOO_SHI_YEONG_NPC_FOOLSDAY_NULL","text":{"KOREA":"아하하, 이런 일이 있을 줄 알았으면 팝콘이라도 가져올 걸 그랬네요.","JPN":"アハハ、こんな展開になると知っていたならポップコーンでも持ってきたのに。","ENG":"Hah hah, I should have brought some popcorn.","TWN":"啊啊啊，早知道有這種趣事，就該帶些爆米花洋芋片來啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YEONG_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":" ……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L33_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"흥! 일개 불순분자 스파이에게 게임을 만든 이 몸이 질 리가 없지!","JPN":"ふん！　一介のスパイ程度にゲームを作ったこの私が負けるわけがない！","ENG":"Hmpf! There's no way a mere spy like you could beat me, the designer of this game!","TWN":"哼！對一個不良分子間諜，身為製作遊戲的我才不可能輸啊！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GAP_NPC_ZHUGE_NULL","text":{"KOREA":"어디 한 번 덤벼봐라!","JPN":"かかってきたまえ！","ENG":"Come at me, if you dare!","TWN":"放馬過來吧！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_NPC_ZHUGE_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};